item.aggregated_output:
  1: // WORKSTATE 상태 전이의 유일한 writer.
  2: // prepare: 전이 계획(envelope+candidate)을 outputs/state-transition/에 기록한다.
  3: // apply: reconciliation-먼저, 멱등 결속, rollback, FATAL 분류 포함 전이를 실행한다.
  4: using System.Globalization;
  5: using System.Security.Cryptography;
  6: using System.Text;
  7: using System.Text.Encodings.Web;
  8: using System.Text.Json;
  9: using System.Text.Json.Nodes;
 10: using System.Text.RegularExpressions;
 11: 
 12: internal static class StateApplierCli
 13: {
 14:     private static readonly JsonSerializerOptions WriteOptions = new()
 15:     {
 16:         WriteIndented = true,
 17:         Encoder = JavaScriptEncoder.UnsafeRelaxedJsonEscaping,
 18:     };
 19: 
 20:     private static readonly HashSet<string> ValidStatuses = new(StringComparer.OrdinalIgnoreCase)
 21:     {
 22:         "waiting", "in_progress", "verifying", "completed", "blocked",
 23:     };
 24: 
 25:     // 허용 전이 화이트리스트 — 이 표 밖의 전이는 전부 거부(completed는 terminal).
 26:     private static readonly Dictionary<string, HashSet<string>> AllowedTransitions = new(StringComparer.OrdinalIgnoreCase)
 27:     {
 28:         ["waiting"] = new(StringComparer.OrdinalIgnoreCase) { "in_progress", "blocked" },
 29:         ["in_progress"] = new(StringComparer.OrdinalIgnoreCase) { "verifying", "blocked", "waiting" },
 30:         ["verifying"] = new(StringComparer.OrdinalIgnoreCase) { "completed", "in_progress", "blocked" },
 31:         ["blocked"] = new(StringComparer.OrdinalIgnoreCase) { "waiting", "in_progress", "verifying" },
 32:         ["completed"] = new(StringComparer.OrdinalIgnoreCase) { },
 33:     };
 34: 
 35:     // nextActions 필수 status 목록(completed 제외).
 36:     private static readonly HashSet<string> NextActionsRequired = new(StringComparer.OrdinalIgnoreCase)
 37:     {
 38:         "waiting", "in_progress", "verifying", "blocked",
 39:     };
 40: 
 41:     // 허용 transitionKind 목록 — 이 밖은 unknown-transition-kind로 fail-closed.
 42:     private static readonly HashSet<string> ValidTransitionKinds = new(StringComparer.OrdinalIgnoreCase)
 43:     {
 44:         "NORMAL", "PHASE_CHANGE", "RECOVERY", "REPLAY",
 45:     };
 46: 
 47:     // high-risk transitionKind — receipt ledger 부재로 이번 WP에서 fail-closed.
 48:     private static readonly HashSet<string> HighRiskKinds = new(StringComparer.OrdinalIgnoreCase)
 49:     {
 50:         "PHASE_CHANGE", "RECOVERY", "REPLAY",
 51:     };
 52: 
 53:     // 파싱된 envelope 데이터 레코드.
 54:     private record EnvelopeData(
 55:         int SchemaVersion,
 56:         string TransitionKind,
 57:         string TransitionId,
 58:         string ExpectedPreStateSha256,
 59:         string RequestPath,
 60:         string RequestSha256,
 61:         string EffectiveAt,
 62:         string ExpectedPostStateSha256,
 63:         string? TransitionContractSha256,
 64:         string CandidatePath);
 65: 
 66:     // prepare 부속 명령 옵션.
 67:     private record PrepareOptions(string TransitionId, string RequestPath, bool DryRun);
 68: 
 69:     // apply 부속 명령 옵션.
 70:     private record ApplyOptions(string EnvelopePath, string? VerdictPath, bool DryRun);
 71: 
 72:     // 결정적 test seam — 같은 프로세스의 자기 시험 코드만 설정할 수 있다. production 진입점(CLI·환경변수·설정파일)에서 켤 수 없음.
 73:     internal static Func<string?>? FailAfterWriteHook;
 74: 
 75:     // state-transition 진입점. prepare/apply를 args[1]로 분기하고 그 외는 exit 2.
 76:     internal static int Run(string[] args)
 77:     {
 78:         var sub = args.Length > 1 ? args[1] : "";
 79:         if (string.Equals(sub, "prepare", StringComparison.OrdinalIgnoreCase))
 80:             return RunPrepare(args);
 81:         if (string.Equals(sub, "apply", StringComparison.OrdinalIgnoreCase))
 82:             return RunApply(args);
 83:         Console.Error.WriteLine("{\"error\":\"state-transition usage: prepare --transition-id <id> --request <file> | apply --envelope <file>\"}");
 84:         return 2;
 85:     }
 86: 
 87:     // prepare: WORKSTATE를 읽어 결정적 candidate를 계산하고 envelope+candidate를 출력 디렉터리에 기록한다.
 88:     private static int RunPrepare(string[] args)
 89:     {
 90:         var opts = ParsePrepareArgs(args);
 91:         if (opts is null)
 92:         {
 93:             Console.Error.WriteLine("{\"error\":\"prepare에는 --transition-id, --request 가 필요합니다\"}");
 94:             return 2;
 95:         }
 96:         try
 97:         {
 98:             var root = GitTools.FindRepoRoot();
 99:             var workstatePath = Path.Combine(root, "docs", "handoff", "WORKSTATE.json");
100:             if (!File.Exists(workstatePath)) { WriteError("WORKSTATE.json not found"); return 2; }
101: 
102:             var rawWorkstate = File.ReadAllText(workstatePath, new UTF8Encoding(false));
103:             var workstate = JsonNode.Parse(rawWorkstate)?.AsObject();
104:             if (workstate is null) { WriteError("WORKSTATE.json is not a valid JSON object"); return 2; }
105: 
106:             if (!File.Exists(opts.RequestPath)) { WriteError($"request file not found: {opts.RequestPath}"); return 2; }
107:             var rawRequest = File.ReadAllText(opts.RequestPath, new UTF8Encoding(false));
108:             var request = JsonNode.Parse(rawRequest)?.AsObject();
109:             if (request is null) { WriteError("request JSON must be a JSON object"); return 2; }
110: 
111:             // 해시 계산 + effectiveAt 발급 (NORMAL은 prepare가 현재 UTC를 발급, 외부 플래그 없음).
112:             var preStateSha256 = ComputeSha256(rawWorkstate);
113:             var requestSha256 = ComputeSha256(rawRequest);
114:             var effectiveAt = DateTime.UtcNow.ToString("o");
115: 
116:             // 결정적 candidate 계산 — UtcNow 호출 없이 effectiveAt을 파라미터로 받는다.
117:             var candidate = BuildCandidate(workstate, request, opts.TransitionId, effectiveAt);
118:             var candidateBytes = Encoding.UTF8.GetBytes(candidate.ToJsonString(WriteOptions));
119:             var postStateSha256 = Convert.ToHexString(SHA256.HashData(candidateBytes)).ToLowerInvariant();
120:             var contractHash = ComputeContractHash(
121:                 opts.TransitionId, "NORMAL", requestSha256, preStateSha256, postStateSha256, effectiveAt);
122: 
123:             if (opts.DryRun)
124:             {
125:                 Console.WriteLine(new JsonObject
126:                 {
127:                     ["ok"] = true, ["dryRun"] = true,
128:                     ["transitionId"] = opts.TransitionId,
129:                     ["preStateSha256"] = preStateSha256,
130:                     ["expectedPostStateSha256"] = postStateSha256,
131:                     ["transitionContractSha256"] = contractHash,
132:                 }.ToJsonString(WriteOptions));
133:                 return 0;
134:             }
135: 
136:             return WritePrepareOutput(root, opts, preStateSha256, requestSha256, postStateSha256, contractHash, candidateBytes, effectiveAt);
137:         }
138:         catch (Exception ex)
139:         {
140:             Console.Error.WriteLine($"{{\"error\":\"state-transition prepare 실패: {ex.Message}\"}}");
141:             return 2;
142:         }
143:     }
144: 
145:     // envelope+candidate 파일을 outputs/state-transition/에 기록하고 결과를 출력한다.
146:     private static int WritePrepareOutput(
147:         string root, PrepareOptions opts, string preStateSha256, string requestSha256,
148:         string postStateSha256, string contractHash, byte[] candidateBytes, string effectiveAt)
149:     {
150:         var outDir = Path.Combine(root, "outputs", "state-transition");
151:         Directory.CreateDirectory(outDir);
152:         var safeTid = Regex.Replace(opts.TransitionId, @"[^\w\-]", "_");
153: 
154:         // candidate 파일 기록 — evidence용. apply는 이 파일을 canonical write에 쓰지 않는다.
155:         var candidatePath = Path.Combine(outDir, $"{safeTid}.candidate.json");
156:         File.WriteAllBytes(candidatePath, candidateBytes);
157: 
158:         var envelope = new JsonObject
159:         {
160:             ["schemaVersion"] = 1,
161:             ["transitionKind"] = "NORMAL",
162:             ["transitionId"] = opts.TransitionId,
163:             ["expectedPreStateSha256"] = preStateSha256,
164:             ["requestPath"] = opts.RequestPath,
165:             ["requestSha256"] = requestSha256,
166:             ["effectiveAt"] = effectiveAt,
167:             ["expectedPostStateSha256"] = postStateSha256,
168:             ["transitionContractSha256"] = contractHash,
169:             ["candidatePath"] = candidatePath,
170:         };
171: 
172:         var envelopePath = Path.Combine(outDir, $"{safeTid}.envelope.json");
173:         File.WriteAllText(envelopePath, envelope.ToJsonString(WriteOptions), new UTF8Encoding(false));
174: 
175:         Console.WriteLine(new JsonObject
176:         {
177:             ["ok"] = true,
178:             ["transitionId"] = opts.TransitionId,
179:             ["envelopePath"] = envelopePath,
180:             ["candidatePath"] = candidatePath,
181:             ["preStateSha256"] = preStateSha256,
182:             ["expectedPostStateSha256"] = postStateSha256,
183:             ["transitionContractSha256"] = contractHash,
184:         }.ToJsonString(WriteOptions));
185:         return 0;
186:     }
187: 
188:     // apply: reconciliation-먼저 순서로 WORKSTATE에 전이를 적용한다. rollback + FATAL 분류 포함.
189:     private static int RunApply(string[] args)
190:     {
191:         var opts = ParseApplyArgs(args);
192:         if (opts is null)
193:         {
194:             Console.Error.WriteLine("{\"error\":\"apply에는 --envelope 이 필요합니다\"}");
195:             return 2;
196:         }
197: 
198:         // Envelope 읽기 — 이 단계는 atomic write 전이므로 예외 발생 시 rollback 불필요.
199:         var envelope = ReadEnvelope(opts.EnvelopePath);
200:         if (envelope is null) return 2;
201: 
202:         // unknown transitionKind는 fail-closed — NORMAL/PHASE_CHANGE/RECOVERY/REPLAY 외 거부.
203:         if (!ValidTransitionKinds.Contains(envelope.TransitionKind))
204:             return Fail(1, envelope.TransitionId, "unknown-transition-kind",
205:                 $"transitionKind='{envelope.TransitionKind}'은 알 수 없는 종류입니다 (허용: NORMAL, PHASE_CHANGE, RECOVERY, REPLAY)");
206: 
207:         // high-risk transitionKind — receipt ledger 부재로 항상 fail-closed.
208:         if (HighRiskKinds.Contains(envelope.TransitionKind))
209:             return Fail(1, envelope.TransitionId, "trusted-human-receipt-required",
210:                 $"transitionKind={envelope.TransitionKind}는 receipt ledger 부재로 이번 WP에서 fail-closed");
211: 
212:         var ctx = LoadWorkstateContext();
213:         if (ctx is null) return 2;
214:         var (root, workstatePath, logPath, rawWorkstateBytes, workstate, rawWorkstateStr) = ctx.Value;
215: 
216:         // Step 1: request sha256 + candidate file hash 검증.
217:         var (_, request, evidenceExit) = VerifyApplyEvidence(envelope);
218:         if (evidenceExit.HasValue) return evidenceExit.Value;
219: 
220:         // Step 2: reconciliation — 실패하면 일반 전이를 거부한다.

220:         // Step 2: reconciliation — 실패하면 일반 전이를 거부한다.
221:         // ★ 순서 정정(§1): reconciliation이 existing-transition보다 먼저여야 가짜 id 공격을 막는다.
222:         ReconciliationResult reconResult;
223:         try { reconResult = HandoffIntegrityChecker.Run(new ReconciliationOptions(workstatePath, logPath)); }
224:         catch (Exception ex) { WriteError($"reconciliation 실행 실패: {ex.Message}"); return 2; }
225: 
226:         if (reconResult.Failures.Count > 0 || reconResult.HarnessErrors.Count > 0)
227:         {
228:             var codes = string.Join("; ", reconResult.Failures.Concat(reconResult.HarnessErrors).Select(f => f.Code));
229:             return Fail(1, envelope.TransitionId, "state-corrupted-preapply", $"reconciliation failed: {codes}");
230:         }
231: 
232:         // Step 3: existing-transition 판정 (idempotent / collision / legacy-unverifiable).
233:         // ★ 순서 정정(§1): existing-transition이 pre-state hash보다 먼저여야 재시도가 산다.
234:         var existingResult = CheckExistingTransition(workstate, reconResult, envelope);
235:         if (existingResult.HasValue) return existingResult.Value;
236: 
237:         // Steps 4-6: candidate 재계산 + 검증 + dry-run.
238:         var (recompCandidate, recompBytes, validateExit) =
239:             RunApplyValidatePhase(envelope, workstate, rawWorkstateStr, request!, opts.DryRun, root);
240:         if (validateExit.HasValue) return validateExit.Value;
241: 
242:         // Steps 7-10: atomic write + post-apply 검사 + v2 log.
243:         return RunApplyCommitPhase(
244:             envelope, workstatePath, logPath,
245:             rawWorkstateBytes, workstate, recompCandidate!, recompBytes!);
246:     }
247: 
248:     // 저장소 루트를 찾고 WORKSTATE를 로드한다. 실패 시 null 반환(오류는 stderr에 기록).
249:     private static (string root, string workstatePath, string logPath, byte[] rawBytes, JsonObject workstate, string rawStr)?
250:         LoadWorkstateContext()
251:     {
252:         try
253:         {
254:             var root = GitTools.FindRepoRoot();
255:             var wsPath = Path.Combine(root, "docs", "handoff", "WORKSTATE.json");
256:             var lPath = Path.Combine(root, "docs", "handoff", "WORKSTATE.applier-log.jsonl");
257:             if (!File.Exists(wsPath)) { WriteError("WORKSTATE.json not found"); return null; }
258:             var bytes = File.ReadAllBytes(wsPath);
259:             var raw = Encoding.UTF8.GetString(bytes);
260:             var ws = JsonNode.Parse(raw)?.AsObject()
261:                 ?? throw new InvalidOperationException("WORKSTATE.json is not a valid JSON object");
262:             return (root, wsPath, lPath, bytes, ws, raw);
263:         }
264:         catch (Exception ex) { WriteError(ex.Message); return null; }
265:     }
266: 
267:     // request sha256 + candidate file hash를 검증한다. 성공 시 (rawRequest, request, null) 반환.
268:     private static (string? rawRequest, JsonObject? request, int? exitCode) VerifyApplyEvidence(EnvelopeData envelope)
269:     {
270:         if (!File.Exists(envelope.RequestPath)) { WriteError($"request file not found: {envelope.RequestPath}"); return (null, null, 2); }
271:         string rawRequest;
272:         JsonObject request;
273:         try
274:         {
275:             rawRequest = File.ReadAllText(envelope.RequestPath, new UTF8Encoding(false));
276:             var actualRequestSha = ComputeSha256(rawRequest);
277:             if (!string.Equals(actualRequestSha, envelope.RequestSha256, StringComparison.OrdinalIgnoreCase))
278:                 return (null, null, Fail(1, envelope.TransitionId, "request-sha256-mismatch",
279:                     "request file changed since prepare"));
280:             request = JsonNode.Parse(rawRequest)?.AsObject()
281:                 ?? throw new InvalidOperationException("request JSON must be a JSON object");
282:         }
283:         catch (Exception ex) { WriteError(ex.Message); return (null, null, 2); }
284: 
285:         if (!File.Exists(envelope.CandidatePath)) { WriteError($"candidate file not found: {envelope.CandidatePath}"); return (null, null, 2); }
286:         try
287:         {
288:             var candidateFileHash = Convert.ToHexString(SHA256.HashData(File.ReadAllBytes(envelope.CandidatePath))).ToLowerInvariant();
289:             if (!string.Equals(candidateFileHash, envelope.ExpectedPostStateSha256, StringComparison.OrdinalIgnoreCase))
290:                 return (null, null, Fail(1, envelope.TransitionId, "candidate-tampered",
291:                     "candidate file hash differs from envelope.expectedPostStateSha256 — evidence may have been tampered"));
292:         }
293:         catch (Exception ex) { WriteError($"candidate 파일 읽기 실패: {ex.Message}"); return (null, null, 2); }
294: 
295:         return (rawRequest, request, null);
296:     }
297: 
298:     // Steps 4-6: candidate 재계산 + hash 검증 + pre-state hash + request 검증 + dry-run 처리.
299:     private static (JsonObject? candidate, byte[]? bytes, int? earlyExit) RunApplyValidatePhase(
300:         EnvelopeData envelope, JsonObject workstate, string rawWorkstateStr,
301:         JsonObject request, bool dryRun, string root)
302:     {
303:         JsonObject recomputedCandidate;
304:         byte[] recomputedBytes;
305:         try
306:         {
307:             // Step 4: 메모리에서 candidate 재계산 + hash 검증 (TOCTOU 방어).
308:             recomputedCandidate = BuildCandidate(workstate, request, envelope.TransitionId, envelope.EffectiveAt);
309:             recomputedBytes = Encoding.UTF8.GetBytes(recomputedCandidate.ToJsonString(WriteOptions));
310:             var recomputedHash = Convert.ToHexString(SHA256.HashData(recomputedBytes)).ToLowerInvariant();
311:             if (!string.Equals(recomputedHash, envelope.ExpectedPostStateSha256, StringComparison.OrdinalIgnoreCase))
312:                 return (null, null, Fail(1, envelope.TransitionId, "candidate-recompute-mismatch",
313:                     "recomputed candidate hash differs — WORKSTATE or request changed since prepare"));
314:         }
315:         catch (Exception ex) { WriteError($"candidate 재계산 실패: {ex.Message}"); return (null, null, 2); }
316: 
317:         // Step 5: pre-state hash 검증 (미적용 ID에 한해 실행).
318:         var currentHash = ComputeSha256(rawWorkstateStr);
319:         if (!string.Equals(currentHash, envelope.ExpectedPreStateSha256, StringComparison.OrdinalIgnoreCase))
320:             return (null, null, Fail(1, envelope.TransitionId, "pre-state-hash-mismatch",
321:                 $"expected={Short(envelope.ExpectedPreStateSha256)} actual={Short(currentHash)}"));
322: 
323:         // Step 6: request 검증.
324:         var validErr = ValidateRequestForApply(request, envelope, workstate, root);
325:         if (validErr is not null)
326:             return (null, null, Fail(1, envelope.TransitionId, "validation-failed", validErr));
327: 
328:         if (dryRun)
329:         {
330:             Console.WriteLine(new JsonObject
331:             {
332:                 ["ok"] = true, ["dryRun"] = true,
333:                 ["transitionId"] = envelope.TransitionId,
334:                 ["previousStatus"] = workstate["status"]?.ToString(),
335:                 ["newStatus"] = recomputedCandidate["status"]?.ToString(),
336:             }.ToJsonString(WriteOptions));
337:             return (null, null, 0);
338:         }
339: 
340:         return (recomputedCandidate, recomputedBytes, null);
341:     }
342: 
343:     // Steps 7-10: preimage 저장 → atomic write → test seam → post-apply 검사 → v2 log append.
344:     private static int RunApplyCommitPhase(
345:         EnvelopeData envelope, string workstatePath, string logPath,
346:         byte[] rawWorkstateBytes, JsonObject workstate, JsonObject recomputedCandidate, byte[] recomputedBytes)
347:     {
348:         // Step 7: preimage 저장 — atomic replace 전에 반드시 저장해야 한다.
349:         var preimage = rawWorkstateBytes;
350:         var preimageHash = Convert.ToHexString(SHA256.HashData(preimage)).ToLowerInvariant();
351: 
352:         // Step 8: atomic replace — 재계산 bytes만 사용(candidate 파일은 evidence, write source 아님).
353:         try { var t = workstatePath + ".stateapplier.tmp"; File.WriteAllBytes(t, recomputedBytes); File.Move(t, workstatePath, overwrite: true); }
354:         catch (Exception ex) { WriteError($"atomic write 실패: {ex.Message}"); return 2; }
355: 
356:         // 결정적 test seam — in-process 훅만 허용. 환경변수는 읽지 않는다.
357:         var seamFail = FailAfterWriteHook?.Invoke();
358:         if (seamFail is not null)
359:             return Rollback(workstatePath, logPath, preimage, preimageHash, envelope, seamFail);
360: 
361:         // Step 9: 적용후 검사 — 항상 projection 실행.
362:         var projExit = ProjectionCli.Run(["projection"]);
363:         if (projExit != 0)
364:             return Rollback(workstatePath, logPath, preimage, preimageHash, envelope, "projection-failed");
365: 
366:         // 내부 checker — PendingTransitionId로 pending 면제 경로를 실증한다.
367:         ReconciliationResult reconAfter;
368:         try { reconAfter = HandoffIntegrityChecker.Run(new ReconciliationOptions(workstatePath, logPath, envelope.TransitionId)); }
369:         catch (Exception ex)
370:         {
371:             return Rollback(workstatePath, logPath, preimage, preimageHash, envelope,
372:                 $"post-apply checker 실행 실패: {ex.Message}");
373:         }
374: 
375:         if (reconAfter.Failures.Count > 0 || reconAfter.HarnessErrors.Count > 0)
376:         {
377:             var codes = string.Join("; ", reconAfter.Failures.Concat(reconAfter.HarnessErrors).Select(f => f.Code));
378:             return Rollback(workstatePath, logPath, preimage, preimageHash, envelope,
379:                 $"post-apply-integrity-failed: {codes}");
380:         }
381: 
382:         // Step 10: v2 log append — 성공 경로에서만.
383:         string newSha;
384:         try { newSha = ComputeSha256(File.ReadAllText(workstatePath, new UTF8Encoding(false))); }
385:         catch (Exception ex) { WriteError($"적용 후 hash 계산 실패: {ex.Message}"); return 2; }
386: 
387:         var logContractHash = ComputeContractHash(
388:             envelope.TransitionId, envelope.TransitionKind, envelope.RequestSha256,
389:             envelope.ExpectedPreStateSha256, newSha, envelope.EffectiveAt);
390:         try
391:         {
392:             AppendApplierLogV2(logPath, envelope.TransitionId, "ok", 0, envelope.TransitionKind,
393:                 envelope.RequestSha256, envelope.ExpectedPreStateSha256, newSha, logContractHash, envelope.EffectiveAt);
394:         }
395:         catch (Exception logEx)
396:         {
397:             Console.Error.WriteLine(new JsonObject
398:             {
399:                 ["fatal"] = "AUDIT_LOG_STATE_UNKNOWN", ["transitionId"] = envelope.TransitionId,
400:                 ["detail"] = $"v2 log append threw: {logEx.Message} — 다음 전이 금지, log 수동 검증 필요",
401:             }.ToJsonString());
402:             return 2;
403:         }
404: 
405:         Console.WriteLine(new JsonObject
406:         {
407:             ["ok"] = true, ["transitionId"] = envelope.TransitionId,
408:             ["previousStatus"] = workstate["status"]?.ToString(),
409:             ["newStatus"] = recomputedCandidate["status"]?.ToString(),
410:             ["workstateSha256"] = newSha,
411:             ["pendingExemptionUsed"] = reconAfter.Metrics?.PendingExemptionApplied,
412:         }.ToJsonString(WriteOptions));
413:         return 0;
414:     }
415: 
416:     // rollback: preimage를 복원하고 FATAL taxonomy에 따라 exit code와 로그를 결정한다.
417:     private static int Rollback(
418:         string workstatePath, string logPath, byte[] preimage, string preimageHash,
419:         EnvelopeData envelope, string failureReason)
420:     {
421:         try
422:         {
423:             File.WriteAllBytes(workstatePath, preimage);
424:             var restoredStr = File.ReadAllText(workstatePath, new UTF8Encoding(false));
425:             var restoredHash = ComputeSha256(restoredStr);
426: 
427:             if (!string.Equals(restoredHash, preimageHash, StringComparison.OrdinalIgnoreCase))
428:             {
429:                 // 복원 후 hash 불일치 — FATAL.
430:                 AppendLogSafe(logPath, envelope.TransitionId, "FATAL_STATE_UNKNOWN", 2);
431:                 Console.Error.WriteLine(new JsonObject
432:                 {
433:                     ["fatal"] = "FATAL_STATE_UNKNOWN", ["transitionId"] = envelope.TransitionId,
434:                     ["detail"] = "preimage 복원 hash 불일치 — 모든 자동작업 중단. HUMAN-INBOX 필요.",
435:                 }.ToJsonString());
436:                 return 2;
437:             }
438: 
439:             // rollback 후 항상 projection 재생성 시도.
440:             var projExit = ProjectionCli.Run(["projection"]);
441:             if (projExit != 0)
442:             {
443:                 AppendLogSafe(logPath, envelope.TransitionId, "STATE_RESTORED_PROJECTION_NOT_VERIFIED", 2);
444:                 Console.Error.WriteLine(new JsonObject
445:                 {
446:                     ["fatal"] = "STATE_RESTORED_PROJECTION_NOT_VERIFIED",
447:                     ["transitionId"] = envelope.TransitionId,
448:                     ["detail"] = "WORKSTATE 복원 성공, projection 재생성 실패 — HUMAN-INBOX 필요.",
449:                 }.ToJsonString());
450:                 return 2;
451:             }
452: 
453:             AppendLogSafe(logPath, envelope.TransitionId, "ROLLED_BACK", 1);
454:             Console.Error.WriteLine(new JsonObject
455:             {
456:                 ["ok"] = false, ["result"] = "ROLLED_BACK",
457:                 ["transitionId"] = envelope.TransitionId,
458:                 ["failureReason"] = failureReason,
459:                 ["restoredHash"] = restoredHash,
460:                 ["detail"] = "WORKSTATE 복원 완료. 전이 효과 없음.",

460:                 ["detail"] = "WORKSTATE 복원 완료. 전이 효과 없음.",
461:             }.ToJsonString());
462:             return 1;
463:         }
464:         catch (Exception ex)
465:         {
466:             // 복원 자체 실패 — FATAL.
467:             AppendLogSafe(logPath, envelope.TransitionId, "FATAL_STATE_UNKNOWN", 2);
468:             Console.Error.WriteLine(new JsonObject
469:             {
470:                 ["fatal"] = "FATAL_STATE_UNKNOWN", ["transitionId"] = envelope.TransitionId,
471:                 ["detail"] = $"preimage 복원 실패: {ex.Message} — 모든 자동작업 중단.",
472:             }.ToJsonString());
473:             return 2;
474:         }
475:     }
