477:     // envelope JSON을 읽어 EnvelopeData로 파싱한다. 실패 시 null 반환.
478:     private static EnvelopeData? ReadEnvelope(string envelopePath)
479:     {
480:         if (!File.Exists(envelopePath)) { WriteError($"envelope file not found: {envelopePath}"); return null; }
481:         JsonObject env;
482:         try
483:         {
484:             env = JsonNode.Parse(File.ReadAllText(envelopePath, new UTF8Encoding(false)))?.AsObject()
485:                 ?? throw new InvalidOperationException("envelope is not a JSON object");
486:         }
487:         catch (Exception ex) { WriteError($"envelope parse 실패: {ex.Message}"); return null; }
488: 
489:         var kind = env["transitionKind"]?.GetValue<string>() ?? "NORMAL";
490:         var tid = env["transitionId"]?.GetValue<string>() ?? "";
491:         if (string.IsNullOrWhiteSpace(tid)) { WriteError("envelope.transitionId missing"); return null; }
492: 
493:         var preHash = env["expectedPreStateSha256"]?.GetValue<string>() ?? "";
494:         var reqPath = env["requestPath"]?.GetValue<string>() ?? "";
495:         var reqSha = env["requestSha256"]?.GetValue<string>() ?? "";
496:         var effAt = env["effectiveAt"]?.GetValue<string>() ?? "";
497:         var postHash = env["expectedPostStateSha256"]?.GetValue<string>() ?? "";
498:         var candidatePath = env["candidatePath"]?.GetValue<string>() ?? "";
499:         var contractSha = env["transitionContractSha256"]?.GetValue<string>();
500: 
501:         if (string.IsNullOrWhiteSpace(preHash) || string.IsNullOrWhiteSpace(reqPath) ||
502:             string.IsNullOrWhiteSpace(reqSha) || string.IsNullOrWhiteSpace(effAt) ||
503:             string.IsNullOrWhiteSpace(postHash) || string.IsNullOrWhiteSpace(candidatePath))
504:         {
505:             WriteError("envelope 필수 필드 누락 (transitionId/expectedPreStateSha256/requestPath/requestSha256/effectiveAt/expectedPostStateSha256/candidatePath)");
506:             return null;
507:         }
508: 
509:         var sv = env["schemaVersion"]?.GetValue<int>() ?? 1;
510:         return new EnvelopeData(sv, kind, tid, preHash, reqPath, reqSha, effAt, postHash, contractSha, candidatePath);
511:     }
