513:     // 전이 ID가 이미 state에 있는지 판정하고 idempotent/collision/envelope-mismatch/legacy-unverifiable exit를 반환한다.
514:     private static int? CheckExistingTransition(
515:         JsonObject workstate, ReconciliationResult reconResult, EnvelopeData envelope)
516:     {
517:         var isInState = workstate["appliedTransitions"] is JsonArray applied &&
518:             applied.OfType<JsonObject>().Any(o =>
519:                 string.Equals(o["id"]?.ToString(), envelope.TransitionId, StringComparison.Ordinal));
520: 
521:         if (!isInState) return null; // 미적용 — 정상 경로로 진행.
522: 
523:         // state에 있음 — log 조회.
524:         reconResult.SuccessLookup.TryGetValue(envelope.TransitionId, out var logInfo);
525:         if (logInfo is null || !logInfo.Exists)
526:         {
527:             // reconciliation이 PASS했으므로 state+log 불일치는 없어야 함 — 방어 코드.
528:             return Fail(1, envelope.TransitionId, "state-corrupted-preapply",
529:                 $"id '{envelope.TransitionId}' in state but not in success log");
530:         }
531: 
532:         if (logInfo.SchemaVersion < 2 || string.IsNullOrWhiteSpace(logInfo.TransitionContractSha256))
533:         {
534:             // v1 log — 내용 결속 검증 불가.
535:             return Fail(1, envelope.TransitionId, "legacy-idempotency-unverifiable",
536:                 $"id '{envelope.TransitionId}'는 v1 log에 있음 — contract binding 검증 불가");
537:         }
538: 
539:         // v2 log — envelope 구성 필드로부터 contract hash를 재계산해 비교한다 (envelope 자기신고 불신).
540:         var computed = ComputeContractHash(
541:             envelope.TransitionId, envelope.TransitionKind, envelope.RequestSha256,
542:             envelope.ExpectedPreStateSha256, envelope.ExpectedPostStateSha256, envelope.EffectiveAt);
543: 
544:         // 재계산값이 log hash와 다르면 — 다른 계약의 transition-id가 충돌함.
545:         if (!string.Equals(computed, logInfo.TransitionContractSha256, StringComparison.OrdinalIgnoreCase))
546:         {
547:             return Fail(1, envelope.TransitionId, "transition-id-collision",
548:                 $"id '{envelope.TransitionId}'는 다른 contract hash로 이미 적용됨");
549:         }
550: 
551:         // envelope 자기신고 hash가 계산값과 다르면 — envelope 위조 탐지.
552:         if (!string.IsNullOrWhiteSpace(envelope.TransitionContractSha256) &&
553:             !string.Equals(envelope.TransitionContractSha256, computed, StringComparison.OrdinalIgnoreCase))
554:         {
555:             return Fail(1, envelope.TransitionId, "envelope-contract-mismatch",
556:                 $"envelope.transitionContractSha256이 계산값과 다릅니다 — 위조 또는 수정됨");
557:         }
558: 
559:         // 동일 contract — idempotent.
560:         return ReportIdempotent(envelope.TransitionId);
561:     }
