594:     // apply 경로용 request 검증 — human-decision 플래그 없이 동작한다.
595:     private static string? ValidateRequestForApply(
596:         JsonObject request, EnvelopeData envelope, JsonObject current, string root)
597:     {
598:         if (request["phaseId"] is JsonNode ph && !Regex.IsMatch(ph.ToString(), @"^P\d{2,}$"))
599:             return $"phaseId '{ph}'는 canonical 형식(P00, P01 …)이 아닙니다";
600:         if (request["wpId"] is JsonNode wp && !Regex.IsMatch(wp.ToString(), @"^WP-\d{2,}$"))
601:             return $"wpId '{wp}'는 canonical 형식(WP-00 …)이 아닙니다";
602:         if (request["diId"] is JsonNode di && !Regex.IsMatch(di.ToString(), @"^DI-\d{2}-\d{2,}$"))
603:             return $"diId '{di}'는 canonical 형식(DI-00-05 …)이 아닙니다";
604: 
605:         var newStatus = request["status"]?.ToString() ?? current["status"]?.ToString() ?? "";
606:         if (!ValidStatuses.Contains(newStatus))
607:             return $"status '{newStatus}'는 허용 목록에 없습니다";
608: 
609:         var currentStatus = current["status"]?.ToString() ?? "";
610:         var currentDiId = current["diId"]?.ToString() ?? "";
611:         var requestDiId = request["diId"]?.ToString();
612: 
613:         var transErr = ValidateStatusTransition(currentStatus, newStatus, currentDiId, requestDiId);
614:         if (transErr is not null) return transErr;
615: 
616:         var newBlockers = request["blockers"] as JsonArray ?? current["blockers"] as JsonArray ?? new JsonArray();
617:         var newNext = request["nextActions"] as JsonArray ?? current["nextActions"] as JsonArray ?? new JsonArray();
618: 
619:         if (string.Equals(newStatus, "blocked", StringComparison.OrdinalIgnoreCase) && newBlockers.Count == 0)
620:             return "status=blocked인데 blockers가 비어있습니다";
621:         if (NextActionsRequired.Contains(newStatus) && newNext.Count == 0)
622:             return $"status={newStatus}인데 nextActions가 비어있습니다";
623: 
624:         if (string.Equals(newStatus, "completed", StringComparison.OrdinalIgnoreCase))
625:         {
626:             var targetDiId = requestDiId ?? currentDiId;
627:             var wsUpdatedAt = current["updatedAt"]?.ToString() ?? "";
628:             var verdictErr = ValidateVerdict(null, targetDiId, wsUpdatedAt);
629:             if (verdictErr is not null) return verdictErr;
630:         }
631: 
632:         var curPhase = current["phaseId"]?.ToString();
633:         var newPhase = request["phaseId"]?.ToString();
634:         if (newPhase is not null && !string.Equals(newPhase, curPhase, StringComparison.OrdinalIgnoreCase))
635:             return $"Phase 전이({curPhase} → {newPhase})는 transitionKind=PHASE_CHANGE를 사용하세요 (이번 WP fail-closed)";
636: 
637:         if (!string.IsNullOrWhiteSpace(root))
638:         {
639:             var wpId = request["wpId"]?.ToString() ?? current["wpId"]?.ToString();
640:             if (!string.IsNullOrWhiteSpace(wpId))
641:             {
642:                 var regErr = ValidateWpRegistry(root, wpId);
643:                 if (regErr is not null) return regErr;
644:             }
645:         }
646:         return null;
647:     }
