649:     // DI 경계와 전이 그래프를 검사한다.
650:     private static string? ValidateStatusTransition(
651:         string currentStatus, string newStatus, string currentDiId, string? requestDiId)
652:     {
653:         var isNewDi = requestDiId is not null &&
654:                       !string.Equals(requestDiId, currentDiId, StringComparison.OrdinalIgnoreCase);
655: 
656:         if (isNewDi)
657:         {
658:             if (!string.Equals(currentStatus, "completed", StringComparison.OrdinalIgnoreCase))
659:                 return $"새 DI 착수({currentDiId} → {requestDiId})는 현재 DI가 completed여야 합니다(현재: {currentStatus})";
660:             if (!string.Equals(newStatus, "waiting", StringComparison.OrdinalIgnoreCase) &&
661:                 !string.Equals(newStatus, "in_progress", StringComparison.OrdinalIgnoreCase))
662:                 return $"새 DI 착수 시 status는 waiting 또는 in_progress만 허용합니다(요청: {newStatus})";
663:             return null;
664:         }
665: 
666:         if (string.Equals(currentStatus, newStatus, StringComparison.OrdinalIgnoreCase)) return null;
667: 
668:         // completed는 terminal.
669:         if (string.Equals(currentStatus, "completed", StringComparison.OrdinalIgnoreCase))
670:             return $"completed 상태 전이({currentStatus} → {newStatus})는 허용되지 않습니다 — completed는 terminal 상태입니다";
671: 
672:         if (AllowedTransitions.TryGetValue(currentStatus, out var allowed) && !allowed.Contains(newStatus))
673:         {
674:             var allowedStr = allowed.Count > 0 ? string.Join(", ", allowed) : "없음(terminal)";
675:             return $"status 전이 {currentStatus} → {newStatus}는 허용되지 않습니다(허용: {allowedStr})";
676:         }
677:         return null;
678:     }
