680:     // gate.json 형식·gateVerdict·failureCount·taskId 일치·stale 여부를 검증한다.
681:     private static string? ValidateVerdict(string? verdictPath, string targetDiId, string workstateUpdatedAt)
682:     {
683:         if (string.IsNullOrWhiteSpace(verdictPath))
684:             return "status=completed 전이에는 --verdict 파일이 필요합니다";
685: 
686:         var normalized = verdictPath.Replace('\\', '/');
687:         var fileName = Path.GetFileName(normalized);
688:         if (!fileName.EndsWith(".gate.json", StringComparison.OrdinalIgnoreCase))
689:             return $"verdict 경로는 outputs/gates/<taskId>.gate.json 형식이어야 합니다(받음: {verdictPath})";
690: 
691:         var dirPart = Path.GetDirectoryName(normalized)?.Replace('\\', '/') ?? "";
692:         if (!dirPart.EndsWith("outputs/gates", StringComparison.OrdinalIgnoreCase))
693:             return $"verdict 경로는 outputs/gates/<taskId>.gate.json 형식이어야 합니다(받음: {verdictPath})";
694: 
695:         if (!File.Exists(verdictPath)) return $"verdict file not found: {verdictPath}";
696: 
697:         var gateJson = JsonNode.Parse(File.ReadAllText(verdictPath))?.AsObject();
698:         if (gateJson is null) return "gate JSON이 유효하지 않습니다";
699: 
700:         var gateVerdict = gateJson["gateVerdict"]?.ToString();
701:         if (!string.Equals(gateVerdict, "PASS", StringComparison.OrdinalIgnoreCase))
702:             return $"gate verdict가 PASS가 아닙니다(gateVerdict={gateVerdict ?? "null"})";
703: 
704:         var failureCount = gateJson["failureCount"]?.GetValue<int>() ?? -1;
705:         if (failureCount != 0) return $"gate failureCount가 0이 아닙니다(failureCount={failureCount})";
706: 
707:         var gateTaskId = gateJson["taskId"]?.ToString();
708:         if (!string.Equals(gateTaskId, targetDiId, StringComparison.OrdinalIgnoreCase))
709:             return $"gate taskId({gateTaskId ?? "null"})가 전이 대상 DI({targetDiId})와 일치하지 않습니다";
710: 
711:         var createdAtStr = gateJson["createdAt"]?.ToString();
712:         if (createdAtStr is not null &&
713:             DateTimeOffset.TryParse(createdAtStr, out var createdAt) &&
714:             DateTime.TryParse(workstateUpdatedAt, out var wsUpdated) &&
715:             createdAt.Date < wsUpdated.Date)
716:         {
717:             return $"gate 증거가 WORKSTATE updatedAt({workstateUpdatedAt})보다 오래됐습니다(gate createdAt={createdAt:yyyy-MM-dd})";
718:         }
719:         return null;
720:     }
