854:     // 실패 결과를 stderr에 출력하고 지정 exit code를 반환한다.
855:     private static int Fail(int exitCode, string transitionId, string reason, string detail)
856:     {
857:         Console.Error.WriteLine(new JsonObject
858:         {
859:             ["ok"] = false,
