  1: // state-transition 활성 경로에서 prepare/apply로 정렬되지 않은 옛 단일-샷 호출을 탐지한다.
  2: using System.Text.Encodings.Web;
  3: using System.Text.Json;
  4: using System.Text.Json.Nodes;
  5: using System.Text.RegularExpressions;
  6: 
  7: internal static class StateTransitionCallsiteCheckCli
  8: {
  9:     private static readonly JsonSerializerOptions WriteOptions = new()
 10:     {
 11:         WriteIndented = true,
 12:         Encoder = JavaScriptEncoder.UnsafeRelaxedJsonEscaping,
 13:     };
 14: 
 15:     // 활성 경로로 간주하는 파일 확장자 — 역사적 증거 파일은 allowlist로 면제.
 16:     private static readonly string[] ActiveExtensions =
 17:     [
 18:         ".cs", ".ps1", ".sh", ".cmd", ".bat",
 19:         ".json", ".yaml", ".yml",
 20:         ".md",
 21:     ];
 22: 
 23:     // 역사적 증거 경로 allowlist — 이 경로 아래 파일은 legacyCallsiteCount에 포함하지 않는다.
 24:     // 경로 접두사가 아니라 명시 경로 목록 — 활성 경로(outputs/launch/ 등)는 포함하지 않는다.
 25:     private static readonly string[] HistoricalPrefixes =
 26:     [
 27:         "docs/handoff/sessions/",
 28:         "docs/handoff/WORKSTATE.applier-log.jsonl",
 29:         "docs/handoff/RECOVERY.md",
 30:         "docs/handoff/queue/",
 31:         "docs/verification/",
 32:         "docs/wiki/",
 33:         "outputs/review/",
 34:         "outputs/review-log.md",
 35:         "outputs/reviewer-log.md",
 36:         "HUMAN-INBOX.md",
 37:     ];
 38: 
 39:     // 옛 단일-샷 호출 패턴 — state-transition 뒤에 --transition-id 또는 --expected-workstate-sha256이 오는 경우.
 40:     private static readonly Regex LegacyCallPattern = new(
 41:         @"state-transition\s+--(?:transition-id|expected-workstate-sha256)",
 42:         RegexOptions.Compiled | RegexOptions.IgnoreCase);
 43: 
 44:     // 활성 경로에서 옛 단일-샷 state-transition 호출을 탐지한다.
 45:     internal static int Run(string[] args)
 46:     {
 47:         try
 48:         {
 49:             var root = GitTools.FindRepoRoot();
 50:             var result = ScanCallsites(root);
 51: 
 52:             Console.WriteLine(result.ToJsonString(WriteOptions));
 53:             return result["legacyCallsiteCount"]?.GetValue<int>() == 0 ? 0 : 1;
 54:         }
 55:         catch (Exception ex)
 56:         {
 57:             Console.Error.WriteLine($"{{\"error\":\"state-transition-callsite-check 실패: {ex.Message}\"}}");
 58:             return 2;
 59:         }
 60:     }
 61: 
 62:     // 저장소 전체를 스캔해 legacy callsite 수를 반환한다.
 63:     private static JsonObject ScanCallsites(string root)
 64:     {
 65:         var legacyPaths = new List<string>();
 66:         var historicalPaths = new List<string>();
 67:         var scannedCount = 0;
 68: 
 69:         foreach (var filePath in EnumerateActiveFiles(root))
 70:         {
 71:             var relPath = ToRelative(filePath, root);
 72:             if (IsHistorical(relPath))
 73:             {
 74:                 if (ContainsLegacyCall(filePath))
 75:                     historicalPaths.Add(relPath);
 76:                 continue;
 77:             }
 78: 
 79:             scannedCount++;
 80:             if (ContainsLegacyCall(filePath))
 81:                 legacyPaths.Add(relPath);
 82:         }
 83: 
 84:         var classified = legacyPaths.Concat(historicalPaths.Select(p => "[historical] " + p)).ToArray();
 85: 
 86:         return new JsonObject
 87:         {
 88:             ["legacyCallsiteCount"] = legacyPaths.Count,
 89:             ["historicalReferenceCount"] = historicalPaths.Count,
 90:             ["scannedActiveFiles"] = scannedCount,
 91:             ["classifiedPaths"] = new JsonArray(classified.Select(p => (JsonNode?)p).ToArray()),
 92:         };
 93:     }
 94: 
 95:     // 검사 대상 활성 파일을 열거한다.
 96:     private static IEnumerable<string> EnumerateActiveFiles(string root)
 97:     {
 98:         var scanDirs = new[]
 99:         {
100:             Path.Combine(root, "server"),
101:             Path.Combine(root, "scripts"),
102:             Path.Combine(root, "outputs"),
103:             Path.Combine(root, "docs"),
104:             Path.Combine(root, ".claude"),
105:             Path.Combine(root, ".github"),
106:         };
107: 
108:         foreach (var dir in scanDirs.Where(Directory.Exists))
109:         {
110:             foreach (var file in Directory.EnumerateFiles(dir, "*", SearchOption.AllDirectories))
111:             {
112:                 var ext = Path.GetExtension(file).ToLowerInvariant();
113:                 if (ActiveExtensions.Contains(ext))
114:                     yield return file;
115:             }
116:         }
117: 
118:         // 루트의 스크립트·manifest 파일도 포함.
119:         foreach (var ext in new[] { "*.ps1", "*.sh", "*.cmd", "*.bat", "*.json", "*.yaml", "*.yml" })
120:         {
121:             foreach (var file in Directory.GetFiles(root, ext))
122:                 yield return file;
123:         }
124:     }
125: 
126:     // 경로가 역사적 증거 allowlist에 속하는지 확인한다.
127:     private static bool IsHistorical(string relPath)
128:     {
129:         var normalized = relPath.Replace('\\', '/');
130:         return HistoricalPrefixes.Any(prefix =>
131:             normalized.StartsWith(prefix, StringComparison.OrdinalIgnoreCase) ||
132:             string.Equals(normalized, prefix.TrimEnd('/'), StringComparison.OrdinalIgnoreCase));
133:     }
134: 
135:     // 파일 내용에 legacy single-shot 패턴이 있는지 확인한다.
136:     private static bool ContainsLegacyCall(string filePath)
137:     {
138:         try
139:         {
140:             var content = File.ReadAllText(filePath);
141:             return LegacyCallPattern.IsMatch(content);
142:         }
143:         catch { return false; }
144:     }
145: 
146:     // 절대 경로를 저장소 루트 기준 상대 경로로 변환한다.
147:     private static string ToRelative(string absPath, string root)
148:     {
149:         if (absPath.StartsWith(root, StringComparison.OrdinalIgnoreCase))
150:             return absPath[(root.Length + 1)..].Replace('\\', '/');
151:         return absPath.Replace('\\', '/');
152:     }
153: }

